CREATE TABLE IF NOT EXISTS schema_migrations (version INTEGER PRIMARY KEY, applied_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS organizations (id INTEGER PRIMARY KEY, slug TEXT NOT NULL UNIQUE, name TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS teams (id INTEGER PRIMARY KEY, organization_id INTEGER NOT NULL REFERENCES organizations(id) ON DELETE CASCADE, slug TEXT NOT NULL, name TEXT NOT NULL, UNIQUE(organization_id, slug));
CREATE TABLE IF NOT EXISTS users (id INTEGER PRIMARY KEY, email TEXT NOT NULL UNIQUE, display_name TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS roles (id INTEGER PRIMARY KEY, name TEXT NOT NULL UNIQUE);
CREATE TABLE IF NOT EXISTS permissions (id INTEGER PRIMARY KEY, name TEXT NOT NULL UNIQUE);
CREATE TABLE IF NOT EXISTS products (id INTEGER PRIMARY KEY, organization_id INTEGER REFERENCES organizations(id) ON DELETE CASCADE, slug TEXT NOT NULL UNIQUE, name TEXT NOT NULL, description TEXT NOT NULL DEFAULT '');
CREATE TABLE IF NOT EXISTS product_versions (id INTEGER PRIMARY KEY, product_id INTEGER NOT NULL REFERENCES products(id) ON DELETE CASCADE, version TEXT NOT NULL, UNIQUE(product_id, version));
CREATE TABLE IF NOT EXISTS version_aliases (product_version_id INTEGER NOT NULL REFERENCES product_versions(id) ON DELETE CASCADE, alias TEXT NOT NULL, PRIMARY KEY(product_version_id, alias));
CREATE TABLE IF NOT EXISTS documents (id INTEGER PRIMARY KEY, product_version_id INTEGER NOT NULL REFERENCES product_versions(id) ON DELETE CASCADE, path TEXT NOT NULL, title TEXT NOT NULL, owner TEXT NOT NULL DEFAULT '', source TEXT NOT NULL, html TEXT NOT NULL, updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, UNIQUE(product_version_id, path));
CREATE TABLE IF NOT EXISTS document_tags (document_id INTEGER NOT NULL REFERENCES documents(id) ON DELETE CASCADE, tag TEXT NOT NULL, PRIMARY KEY(document_id, tag));
CREATE VIRTUAL TABLE IF NOT EXISTS documents_fts USING fts5(title, source, tags);
